<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --s3-endpoint</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://minio.local.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
